import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaArrowLeft, FaMapPin, FaClock, FaCalendar, FaPhone, FaGlobe, FaFacebook, FaEnvelope, FaStar } from 'react-icons/fa';
import { api } from '../api/axios';
import EventCard from '../components/EventCard';

export default function EventDetailNew() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [relatedEvents, setRelatedEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const fetchEventDetails = async () => {
      try {
        const response = await api.get(`/events/${id}/`);
        setEvent(response.data);

        // Fetch related events in the same category - limit to 20
        const relatedResponse = await api.get('/events/', {
          params: { category: response.data.category, limit: 20 }
        });
        setRelatedEvents((relatedResponse.data.results || relatedResponse.data).filter(evt => evt.id !== id));
      } catch (error) {
        console.error('Failed to fetch event:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetails();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#191919' }}>
        <p className="text-gray-400">Loading event details...</p>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#191919' }}>
        <p className="text-gray-400">Event not found</p>
      </div>
    );
  }

  return (
    <div style={{ background: "#191919", minHeight: "100vh" }}>
      {/* Back Button */}
      <div className="border-b" style={{ borderColor: "#2a2a2a", background: "#0a0a0a", padding: "16px" }}>
        <div className="max-w-6xl mx-auto px-4 flex items-center gap-2">
          <button
            onClick={() => navigate(-1)}
            className="text-gray-400 hover:text-white transition flex items-center gap-2"
          >
            <FaArrowLeft size={18} />
            <span>Back</span>
          </button>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 py-12">
        {/* Title Section */}
        <div className="mb-12">
          <p className="text-xs font-semibold tracking-widest uppercase mb-3" style={{ color: "#ff00e0" }}>
            {event.category_name}
          </p>
          <h1 className="text-4xl md:text-5xl font-extrabold text-white mb-4 leading-tight">
            {event.title}
          </h1>
          <p className="text-gray-400 text-lg max-w-2xl">
            {event.city && `📍 ${event.city}`}
          </p>
        </div>

        {/* Photo Gallery */}
        {event.image && (
          <div className="rounded-xl overflow-hidden mb-12" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
            <div className="aspect-video bg-black flex items-center justify-center overflow-hidden">
              <img
                src={event.image}
                alt={event.title}
                className="w-full h-full object-cover"
              />
            </div>
          </div>
        )}

        <div className="grid md:grid-cols-3 gap-12 mb-12">
          {/* Main Content */}
          <div className="md:col-span-2">
            {/* Description */}
            <div className="mb-12">
              <h2 className="text-2xl font-bold text-white mb-4">About This Event</h2>
              <p className="text-gray-300 leading-relaxed text-lg">
                {event.description}
              </p>
            </div>

            {/* Event Information */}
            <div className="rounded-xl p-8 mb-12" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
              <h3 className="text-xl font-bold text-white mb-6">Event Details</h3>
              <div className="space-y-4">
                <div className="flex items-start gap-4">
                  <FaCalendarAlt size={20} className="text-gray-400 mt-1 flex-shrink-0" />
                  <div>
                    <p className="text-gray-400 text-sm">Date</p>
                    <p className="text-white font-semibold">
                      {format(eventDate, "EEEE, MMMM d, yyyy")}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-4">
                  <FaClock size={20} className="text-gray-400 mt-1 flex-shrink-0" />
                  <div>
                    <p className="text-gray-400 text-sm">Time</p>
                    <p className="text-white font-semibold">
                      {format(eventDate, "h:mm a")}
                      {eventEndDate && ` - ${format(eventEndDate, "h:mm a")}`}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-4">
                  <FaMapMarkerAlt size={20} className="text-gray-400 mt-1 flex-shrink-0" />
                  <div>
                    <p className="text-gray-400 text-sm">Location</p>
                    <p className="text-white font-semibold">{event.location}</p>
                    <p className="text-gray-500 text-sm">{event.city}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Organizer Info */}
            <div className="rounded-xl p-8" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
              <h3 className="text-xl font-bold text-white mb-6">Organizer</h3>
              <div className="space-y-4">
                <div>
                  <p className="text-gray-400 text-sm mb-1">Name</p>
                  <p className="text-white font-semibold text-lg">{event.organizer_name}</p>
                </div>
                {event.organizer_email && (
                  <div>
                    <p className="text-gray-400 text-sm mb-1">Email</p>
                    <a href={`mailto:${event.organizer_email}`} className="text-gray-300 hover:text-pink-500 transition">
                      {event.organizer_email}
                    </a>
                  </div>
                )}
                {event.organizer_phone && (
                  <div>
                    <p className="text-gray-400 text-sm mb-1">Phone</p>
                    <a href={`tel:${event.organizer_phone}`} className="text-gray-300 hover:text-pink-500 transition flex items-center gap-2">
                      <FaPhone size={16} />
                      {event.organizer_phone}
                    </a>
                  </div>
                )}
                {event.website && (
                  <div>
                    <p className="text-gray-400 text-sm mb-1">Website</p>
                    <a href={event.website} target="_blank" rel="noopener noreferrer" className="text-gray-300 hover:text-pink-500 transition flex items-center gap-2">
                      <FaGlobe size={16} />
                      Visit Website
                    </a>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div>
            {/* Share Section */}
            <div className="rounded-xl p-6 mb-6" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <FaShare size={18} />
                Share Event
              </h3>
              <button
                onClick={() => {
                  const url = window.location.href;
                  window.open(`https://www.facebook.com/sharer/sharer.php?u=${url}`, '_blank');
                }}
                className="w-full py-2 px-4 rounded-lg bg-blue-600 hover:bg-blue-700 text-white font-semibold transition flex items-center justify-center gap-2"
              >
                <FaFacebook size={18} />
                Share on Facebook
              </button>
              <button
                onClick={() => {
                  navigator.clipboard.writeText(window.location.href);
                  alert('Link copied to clipboard!');
                }}
                className="w-full py-2 px-4 rounded-lg mt-2 border border-gray-600 hover:border-pink-500 text-white font-semibold transition"
              >
                Copy Link
              </button>
            </div>

            {/* Featured Badge */}
            {event.is_featured && (
              <div className="rounded-xl p-6 mb-6" style={{ background: "rgba(255,0,224,0.1)", border: "1px solid #ff00e0" }}>
                <p className="text-pink-500 font-bold flex items-center gap-2">
                  ⭐ Featured Event
                </p>
              </div>
            )}

            {/* Quick Links */}
            <div className="rounded-xl p-6" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
              <h3 className="text-lg font-bold text-white mb-4">Quick Links</h3>
              <Link to="/" className="block py-2 text-pink-500 hover:text-pink-400 transition font-semibold mb-2">
                ← Back to Events
              </Link>
              <Link to={`/dashboard`} className="block py-2 text-gray-300 hover:text-white transition" >
                My Events
              </Link>
            </div>
          </div>
        </div>

        {/* Related Events */}
        {relatedEvents.length > 0 && (
          <div className="mt-16 pt-12 border-t" style={{ borderColor: "#2a2a2a" }}>
            <div className="flex items-center gap-3 mb-8">
              <span style={{ color: "#ff00e0", fontSize: "20px" }}>★</span>
              <h2 className="text-2xl font-bold text-white">Related Events</h2>
              <div className="flex-1 h-px" style={{ background: "#2a2a2a" }} />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {relatedEvents.map((relEvent) => (
                <Link
                  key={relEvent.id}
                  to={`/events/${relEvent.id}`}
                  className="rounded-lg overflow-hidden group hover:opacity-80 transition"
                  style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}
                >
                  {relEvent.image && (
                    <div className="aspect-video bg-black overflow-hidden">
                      <img
                        src={relEvent.image}
                        alt={relEvent.title}
                        className="w-full h-full object-cover group-hover:scale-105 transition"
                      />
                    </div>
                  )}
                  <div className="p-4">
                    <p className="text-gray-400 text-xs mb-2">{relEvent.category_name}</p>
                    <h3 className="text-white font-bold text-sm mb-2 line-clamp-2">{relEvent.title}</h3>
                    <p className="text-gray-500 text-xs">{format(new Date(relEvent.date), "MMM d, yyyy")}</p>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
